var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이걸로 오늘 봉사시간은 전부 채웠다오.","JPN":" これで今日の分の奉仕活動の時間はすべて満たしました。","ENG":" With this, I have completed my volunteer hours.","TWN":"這樣今天的服務學習時間便已完成。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…괜찮다면, 해가 뜰 무렵까지만 더 머물러도 괜찮겠소?","JPN":" ……差支えなければ、日が昇る時間までもう少し居てもいいですか？","ENG":" ...If you will allow me, could I stay a little longer until the sun rises?","TWN":" …方便的話，可以再多待到天亮為止嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"시시콜콜한 대화를 나눠도 좋고, 그대는 그대의 일에만 몰두하고 있어도 상관없다오.","JPN":" 他愛ない会話をするも良し、すべき仕事に没頭するも良し。","ENG":" We could engage in small talk, or you could continue working. I am indifferent.","TWN":"可以隨便聊聊天，若你想做你的事也無妨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대와 함께 있는 것만으로도, 어쩐지 마음 한구석이 편해지는 느낌이거든.","JPN":" 貴殿と共に居るということだけで、心のどこかが穏やかになりますから。","ENG":" Simply being in your presence makes me feel at ease.","TWN":"只要和你在一起，不知為何心裡就感到很安心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"밤마다 홀로 학교에 남아 업무를 보고 있으면 왠지 모를 갈증을 느껴왔소.","JPN":" 夜ごと一人学校に残って仕事をしていると、訳もなく渇きを感じるのです。","ENG":" Every night I stayed alone at school to complete my tasks, I felt an insatiable thirst.","TWN":"每晚獨自在學校辦公時，總會覺得有種莫名的渴望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"고향에선 한 치 의문도 품지 않았던 이 갈증의 정체를… 아카데미의 친우들과 만난 뒤로 알게 되었다오.","JPN":" 故郷では少しの疑いも抱かなかった渇きの正体が……アカデミーの友人たちと出会ってからわかるようになりました。","ENG":" I never questioned the source of my thirst at home... However, after meeting my classmates at the Academy, I now understand.","TWN":"在老家時從未對這種渴望感到疑惑過…但在遇到學院的朋友後，便開始明白為何會有這種渴望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 그대의 곁을 지키는 밤이면, 그런 갈증도 더 이상 느껴지지 않게 되었소.","JPN":" 貴殿のそばで過ごす夜は、その渇きを感じないということも。","ENG":" Furthermore, I no longer feel that thirst when I am by your side during these nights.","TWN":"而且，每當守在你身旁的夜晚，就不會再感受到這種渴望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"처음엔 단지 봉사시간을 채우기 위해 그대를 도울 뿐이었지만…","JPN":" 初めはただ奉仕の時間を満たすため、貴殿を手伝うだけでしたが……","ENG":" It began as a means for me to meet my volunteer hour quota by assisting you...","TWN":"原本只是想說要完成服務學習時間才幫你的…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어쩌면 이젠 본인 또한 그대의 존재를 필요로 하고 있는 것일지도 모르오.","JPN":" ともすれば今は自分も貴殿の存在を必要としているのかもしれません。","ENG":" Perhaps I have come to require your presence now.","TWN":"現在，或許在下開始變得需要你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그러니 앞으로는, 봉사시간이 아닌 때에도 본인을 부담 없이 대해주면 좋겠구려.","JPN":" ゆえに、これからは奉仕の時間でなくとも自分に気兼ねなく接して欲しいです。","ENG":" Henceforth, I hope that you will contact me for matters beyond volunteer work.","TWN":"因此希望日後就算不是服務學習時間，你也可以自然地對待在下。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};